"use strict";
(function () {
  try {
    window.paceOptions = {
      startOnPageLoad: false,
      restartOnPushState: false,
      restartOnRequestAfter: false,
      ajax: false,
      document: false,
      eventLag: false,
      elements: false,
    };

    var root = document.documentElement;
    var themeStateCore = window.BioTernThemeStateCore || null;

    root.classList.add("theme-preload");

    function clearThemePreloadState() {
      if (!root) {
        return;
      }
      root.classList.remove("theme-preload");
      var preloadStyle = document.getElementById("biotern-theme-preload-style");
      if (preloadStyle && preloadStyle.parentNode) {
        preloadStyle.parentNode.removeChild(preloadStyle);
      }
    }

    if (!document.getElementById("biotern-theme-preload-style")) {
      var style = document.createElement("style");
      style.id = "biotern-theme-preload-style";
      style.textContent =
        "html.theme-preload *,html.theme-preload *::before,html.theme-preload *::after{transition:none!important;animation:none!important;}.pace,.pace .pace-progress,.pace .pace-activity{display:none!important;opacity:0!important;visibility:hidden!important;}";
      document.head.appendChild(style);
    }

    function storageGet(key, fallbackValue) {
      try {
        var value = localStorage.getItem(key);
        return value === null ? fallbackValue : value;
      } catch (e) {
        return fallbackValue;
      }
    }

    function storageSet(key, value) {
      try {
        localStorage.setItem(key, String(value));
        return true;
      } catch (e) {
        return false;
      }
    }

    function storageHasAny(keys) {
      var list = Array.isArray(keys) ? keys : [];
      for (var i = 0; i < list.length; i += 1) {
        if (storageGet(list[i], null) !== null) {
          return true;
        }
      }
      return false;
    }

    function fallbackReadThemePrefs() {
      try {
        var key = "biotern_theme_preferences=";
        var parts = document.cookie ? document.cookie.split(";") : [];
        for (var i = 0; i < parts.length; i += 1) {
          var chunk = parts[i].trim();
          if (chunk.indexOf(key) === 0) {
            var raw = chunk.substring(key.length);
            return JSON.parse(decodeURIComponent(raw));
          }
        }
      } catch (e) {}
      return null;
    }

    function readThemePrefsCookie() {
      if (
        themeStateCore &&
        typeof themeStateCore.readPreferencesCookie === "function"
      ) {
        return themeStateCore.readPreferencesCookie("biotern_theme_preferences");
      }
      return fallbackReadThemePrefs();
    }

    function inferInitialPreferences(serverPrefs) {
      if (
        themeStateCore &&
        typeof themeStateCore.inferInitialPreferences === "function"
      ) {
        return themeStateCore.inferInitialPreferences({
          serverPrefs: serverPrefs,
          storageGet: storageGet,
          storageHasAny: storageHasAny,
        });
      }

      return {
        skin: serverPrefs && serverPrefs.skin === "dark" ? "dark" : "light",
        menu: serverPrefs && serverPrefs.menu === "mini" ? "mini" : "auto",
        font:
          serverPrefs && typeof serverPrefs.font === "string" && serverPrefs.font !== ""
            ? serverPrefs.font
            : "default",
        navigation:
          serverPrefs && serverPrefs.navigation === "dark" ? "dark" : "light",
        header: serverPrefs && serverPrefs.header === "dark" ? "dark" : "light",
        scheme: serverPrefs && serverPrefs.scheme === "blue" ? "blue" : "gray",
      };
    }

    function applyInitialThemeClasses(preferences) {
      if (
        themeStateCore &&
        typeof themeStateCore.applyRootThemeClasses === "function"
      ) {
        themeStateCore.applyRootThemeClasses(root, preferences);
        return;
      }

      var prefs = preferences || {};
      root.classList.remove("app-skin-dark", "app-navigation-dark", "app-header-dark", "app-theme-gray");
      if (prefs.skin === "dark") {
        root.classList.add("app-skin-dark");
      }
      if (prefs.navigation === "dark") {
        root.classList.add("app-navigation-dark");
      }
      if (prefs.header === "dark") {
        root.classList.add("app-header-dark");
      }
      if (prefs.scheme === "gray") {
        root.classList.add("app-theme-gray");
      }
    }

    var prefs = readThemePrefsCookie() || {};
    var initialPrefs = inferInitialPreferences(prefs);
    applyInitialThemeClasses(initialPrefs);

    function getSavedMenuMode() {
      var fallbackMode = (initialPrefs && initialPrefs.menu) || "auto";
      if (themeStateCore && typeof themeStateCore.getSavedMenuMode === "function") {
        return themeStateCore.getSavedMenuMode(storageGet, fallbackMode);
      }

      var menuState = storageGet("nexel-classic-dashboard-menu-mini-theme", null);
      if (menuState === "menu-mini-theme") {
        return "mini";
      }
      if (menuState === "menu-expend-theme") {
        return "expanded";
      }
      return fallbackMode === "mini" || fallbackMode === "expanded" ? fallbackMode : "auto";
    }

    function applySavedMenuMode() {
      var mode = getSavedMenuMode();
      var width = window.innerWidth || document.documentElement.clientWidth || 0;

      if (themeStateCore && typeof themeStateCore.applyMenuModeToRoot === "function") {
        themeStateCore.applyMenuModeToRoot(root, mode, width);
        return;
      }

      if (width <= 1024) {
        root.classList.remove("minimenu");
        return;
      }

      if (mode === "mini") {
        root.classList.add("minimenu");
        return;
      }

      if (mode === "expanded") {
        root.classList.remove("minimenu");
        return;
      }

      if (width >= 1024 && width <= 1600) {
        root.classList.add("minimenu");
      } else if (width > 1600) {
        root.classList.remove("minimenu");
      }
    }

    function syncMenuButtons() {
      var miniBtn = document.getElementById("menu-mini-button");
      var expandBtn = document.getElementById("menu-expend-button");
      if (!miniBtn || !expandBtn) {
        return;
      }

      if (root.classList.contains("minimenu")) {
        miniBtn.style.display = "none";
        expandBtn.style.display = "inline-flex";
      } else {
        expandBtn.style.display = "none";
        miniBtn.style.display = "inline-flex";
      }
    }

    function collapseExpandedMiniNav() {
      if (!root.classList.contains("minimenu")) {
        return;
      }
      var navItems = document.querySelectorAll(".nxl-navigation .nxl-item.nxl-hasmenu");
      for (var i = 0; i < navItems.length; i += 1) {
        var item = navItems[i];
        item.classList.remove("nxl-trigger", "active", "open");

        var children = item.children;
        for (var j = 0; j < children.length; j += 1) {
          var child = children[j];
          if (child.classList && child.classList.contains("nxl-link")) {
            child.classList.remove("nxl-trigger", "active", "open");
          }
          if (child.classList && child.classList.contains("nxl-submenu")) {
            child.style.display = "none";
          }
        }
      }
    }

    function resetExpandedNavState() {
      if (root.classList.contains("minimenu")) {
        return;
      }
      var items = document.querySelectorAll(".nxl-navigation .nxl-item.nxl-hasmenu");
      for (var i = 0; i < items.length; i += 1) {
        items[i].classList.remove("nxl-trigger", "open");
      }
      var subMenus = document.querySelectorAll(".nxl-navigation .nxl-submenu");
      for (var j = 0; j < subMenus.length; j += 1) {
        subMenus[j].style.display = "none";
      }
    }

    function bindMiniNavCollapseHandlers() {
      var nav = document.querySelector(".nxl-navigation");
      if (!nav || nav.__bioternMiniNavBound) {
        return;
      }
      nav.__bioternMiniNavBound = true;

      nav.addEventListener("mouseleave", function () {
        if (!root.classList.contains("minimenu")) {
          return;
        }
        collapseExpandedMiniNav();
        var navContent = nav.querySelector(".navbar-content");
        if (navContent) {
          navContent.scrollTop = 0;
          if (
            navContent.firstElementChild &&
            typeof navContent.firstElementChild.scrollTop === "number"
          ) {
            navContent.firstElementChild.scrollTop = 0;
          }
        }
      });
    }

    function bindMiniNavClickHandler() {
      var nav = document.querySelector(".nxl-navigation");
      if (!nav || nav.__bioternMiniNavClickBound) {
        return;
      }
      nav.__bioternMiniNavClickBound = true;

      function getDirectSubmenu(menuItem) {
        if (!menuItem) {
          return null;
        }
        var children = menuItem.children;
        for (var i = 0; i < children.length; i += 1) {
          var child = children[i];
          if (child.classList && child.classList.contains("nxl-submenu")) {
            return child;
          }
        }
        return null;
      }

      function setMenuItemState(menuItem, shouldOpen) {
        if (!menuItem || !menuItem.classList || !menuItem.classList.contains("nxl-hasmenu")) {
          return;
        }
        var submenu = getDirectSubmenu(menuItem);
        if (shouldOpen) {
          menuItem.classList.add("nxl-trigger");
          if (submenu) {
            submenu.style.display = "block";
          }
          return;
        }
        menuItem.classList.remove("nxl-trigger", "open");
        if (submenu) {
          submenu.style.display = "none";
        }
      }

      nav.addEventListener(
        "click",
        function (event) {
          var desktop = (window.innerWidth || document.documentElement.clientWidth || 0) > 1024;
          if (!desktop) {
            return;
          }

          var link =
            event.target && event.target.closest
              ? event.target.closest(".nxl-item.nxl-hasmenu > .nxl-link")
              : null;
          if (!link) {
            return;
          }

          var menuItem = link.parentElement;
          if (!menuItem || !menuItem.classList.contains("nxl-hasmenu")) {
            return;
          }

          event.preventDefault();
          event.stopPropagation();
          if (event.stopImmediatePropagation) {
            event.stopImmediatePropagation();
          }

          var parentList = menuItem.parentElement;
          var wasOpen = menuItem.classList.contains("nxl-trigger");
          var isMini = root.classList.contains("minimenu");

          if (parentList && parentList.children) {
            for (var i = 0; i < parentList.children.length; i += 1) {
              var sibling = parentList.children[i];
              if (sibling !== menuItem) {
                setMenuItemState(sibling, false);
              }
            }
          }

          if (isMini) {
            setMenuItemState(menuItem, !wasOpen);
            return;
          }

          setMenuItemState(menuItem, !wasOpen);
        },
        true
      );
    }

    function bindMenuToggleButtons() {
      if (document.__bioternMenuToggleBound) {
        return;
      }
      document.__bioternMenuToggleBound = true;

      if (window.jQuery && typeof window.jQuery === "function") {
        try {
          window.jQuery("#menu-mini-button").off("click");
          window.jQuery("#menu-expend-button").off("click");
        } catch (e) {}
      }

      document.addEventListener(
        "click",
        function (event) {
          var target = event && event.target && event.target.closest ? event.target : null;
          if (!target) {
            return;
          }

          var miniBtn = target.closest("#menu-mini-button");
          var expandBtn = target.closest("#menu-expend-button");
          if (!miniBtn && !expandBtn) {
            return;
          }

          event.preventDefault();
          event.stopPropagation();
          if (event.stopImmediatePropagation) {
            event.stopImmediatePropagation();
          }

          if (miniBtn) {
            storageSet("nexel-classic-dashboard-menu-mini-theme", "menu-mini-theme");
            applySavedMenuMode();
            syncMenuButtons();
            collapseExpandedMiniNav();
            return;
          }

          storageSet("nexel-classic-dashboard-menu-mini-theme", "menu-expend-theme");
          applySavedMenuMode();
          syncMenuButtons();
          resetExpandedNavState();
        },
        true
      );
    }

    function enforcePersistentMenu() {
      applySavedMenuMode();
      syncMenuButtons();
      collapseExpandedMiniNav();
    }

    applySavedMenuMode();

    document.addEventListener("DOMContentLoaded", function () {
      enforcePersistentMenu();
      bindMiniNavCollapseHandlers();
      bindMiniNavClickHandler();
      bindMenuToggleButtons();
      clearThemePreloadState();

      window.addEventListener("resize", function () {
        if (window.__bioternThemeMenuPersistTimer) {
          window.clearTimeout(window.__bioternThemeMenuPersistTimer);
        }
        window.__bioternThemeMenuPersistTimer = window.setTimeout(function () {
          enforcePersistentMenu();
        }, 0);
      });

      window.addEventListener("load", function () {
        enforcePersistentMenu();
        clearThemePreloadState();
      });
    });

    if (document.readyState === "complete" || document.readyState === "interactive") {
      clearThemePreloadState();
    }
  } catch (e) {}
})();
